const body = $json.body ?? $json;
if (!body || typeof body !== 'object') throw new Error('Request body must be a JSON object');
const requiredTopLevel = ['task','template','systemInstructions','rules','style','sectionsRequired','property'];
for (const key of requiredTopLevel) {
  if (!(key in body)) throw new Error(`Missing required field: ${key}`);
}
if (body.task !== 'draft_offering_memorandum_sections') throw new Error('Invalid task');
if (!Array.isArray(body.sectionsRequired)) throw new Error('sectionsRequired must be an array');
return [{ json: body }];

const raw = $json;
const content = raw?.choices?.[0]?.message?.content;
if (typeof content !== 'string' || !content.trim()) throw new Error('Model returned empty content');
let parsed;
try { parsed = JSON.parse(content); } catch (error) { throw new Error('Model returned non-JSON content'); }
const sections = parsed.sections || {};
const required = ['executiveSummary','propertyDescription','locationOverview','demographicsSummary','highlights','disclaimer'];
for (const key of required) {
  if (!(key in sections)) throw new Error(`Missing drafted section: ${key}`);
}
if (!Array.isArray(sections.highlights)) throw new Error('sections.highlights must be an array');
if (!Array.isArray(parsed.warnings)) parsed.warnings = [];
if (!Array.isArray(parsed.missingInputs)) parsed.missingInputs = [];
if (!parsed.metadata || typeof parsed.metadata !== 'object') parsed.metadata = {};
if (typeof parsed.metadata.template !== 'string') parsed.metadata.template = $('Validate Ticket 5 Request').item.json.template;
if (typeof parsed.metadata.draftVersion !== 'number') parsed.metadata.draftVersion = 1;
return [{ json: parsed }];
